    kind: "transfer_files",
    sourcePath: tracker.currentSourcePath,
    targetPath: tracker.currentTargetPath,
    bytesTransferred: tracker.transferredBytes,
    totalBytes: tracker.totalBytes,
    percent: final ? 100 : percent,
    speedBytesPerSec,
